 1	import React, { FC } from 'react';
 2	
 3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 4	import { isEmpty } from '@kubevirt-utils/utils/utils';
 5	import { ColumnLayout } from '@openshift-console/dynamic-plugin-sdk';
 6	import { Button, ToolbarGroup, ToolbarItem, Tooltip } from '@patternfly/react-core';
 7	import { ColumnsIcon } from '@patternfly/react-icons';
 8	
 9	import { ColumnManagementModal } from '../ColumnManagementModal/ColumnManagementModal';
10	import { useModal } from '../ModalProvider/ModalProvider';
11	
12	type ColumnManagementProps = {
13	  columnLayout: ColumnLayout;
14	  hideColumnManagement?: boolean;
15	};
16	
17	const ColumnManagement: FC<ColumnManagementProps> = ({ columnLayout, hideColumnManagement }) => {
18	  const { t } = useKubevirtTranslation();
19	  const { createModal } = useModal();
20	
21	  if (isEmpty(columnLayout) || !columnLayout?.id || hideColumnManagement) {
22	    return null;
23	  }
24	
25	  return (
26	    <ToolbarGroup>
27	      <ToolbarItem>
28	        <Tooltip content={t('Manage columns')} trigger="mouseenter">
29	          <Button
30	            onClick={() =>
31	              createModal((props) => (
32	                <ColumnManagementModal {...props} columnLayout={columnLayout} />
33	              ))
34	            }
35	            aria-label={t('Column management')}
36	            data-test="manage-columns"
37	            variant="plain"
38	          >
39	            <ColumnsIcon />
40	          </Button>
41	        </Tooltip>
42	      </ToolbarItem>
43	    </ToolbarGroup>
44	  );
45	};
46	
47	export default ColumnManagement;

